5	High Protein Smoothie	["1 cup spinach", "1 banana", "1 cup Greek yogurt", "1 scoop protein powder", "1 tablespoon peanut butter", "1 cup almond milk"]	["Combine spinach, banana, Greek yogurt, protein powder, peanut butter, and almond milk in a blender.", "Blend until smooth.", "Pour into a glass and enjoy."]	2026-03-04 15:38:08.859035	ianw
6	High Protein Egg and Quinoa Bowl	["1 cup cooked quinoa", "2 large eggs", "1/2 avocado, sliced", "1/4 cup black beans", "1/4 cup diced tomatoes", "Salt and pepper to taste", "Olive oil for cooking"]	["Heat olive oil in a skillet over medium heat.", "Scramble the eggs until fully cooked.", "In a bowl, combine cooked quinoa, scrambled eggs, black beans, and diced tomatoes.", "Top with sliced avocado and season with salt and pepper.", "Serve warm."]	2026-03-04 15:42:23.870087	ianw
9	High Protein Cottage Cheese Bowl	["1 cup cottage cheese", "1/2 cup sliced peaches", "1/4 cup walnuts", "1 tablespoon honey", "1 tablespoon cinnamon"]	["In a bowl, scoop the cottage cheese.", "Top with sliced peaches, walnuts, honey, and sprinkle with cinnamon.", "Mix gently and enjoy."]	2026-03-05 09:20:10.830511	ianw
10	Classic Apple Pie	["2 1/2 cups all-purpose flour", "1 teaspoon salt", "1 teaspoon sugar", "1 cup unsalted butter, chilled and diced", "6 to 8 tablespoons ice water", "6 to 8 apples, peeled, cored, and sliced", "3/4 cup sugar", "2 tablespoons all-purpose flour", "1 teaspoon cinnamon", "1/4 teaspoon nutmeg", "1 tablespoon lemon juice", "1 tablespoon butter"]	["Preheat oven to 425°F (220°C).", "In a bowl, combine flour, salt, and sugar.", "Cut in butter until mixture resembles coarse crumbs.", "Stir in ice water, a tablespoon at a time, until mixture forms a ball.", "Divide dough in half, shape into discs, wrap in plastic, and refrigerate for 4 hours or overnight.", "Roll out one disc to fit the pie pan and place in the pan.", "In a large bowl, toss sliced apples with sugar, flour, cinnamon, nutmeg, and lemon juice.", "Fill the pie crust with the apple mixture and dot with butter.", "Roll out the second disc, place over the filling, seal edges, and cut slits for ventilation.", "Bake in the preheated oven for 15 minutes, reduce temperature to 350°F (175°C), and continue baking for 35 to 45 minutes until apples are soft and crust is golden brown."]	2026-03-05 09:46:23.905806	ianw
11	Buffalo Hot Sauce	["1 cup hot sauce", "1/2 cup unsalted butter", "1 tablespoon white vinegar", "1 teaspoon Worcestershire sauce", "1/4 teaspoon garlic powder", "Salt to taste"]	["Melt the butter in a saucepan over low heat.", "Mix in hot sauce, white vinegar, Worcestershire sauce, and garlic powder.", "Whisk until fully blended and warmed.", "Season with salt as desired.", "Remove from heat and serve or store in an airtight container."]	2026-03-05 11:17:07.817567	ianw
13	Blue Cheese Sauce	["1/2 cup crumbled blue cheese", "1/4 cup sour cream", "1/4 cup mayonnaise", "1 tablespoon lemon juice", "1/2 teaspoon garlic powder", "Salt and pepper to taste"]	["In a bowl, combine blue cheese, sour cream, mayonnaise, and lemon juice.", "Mix until well blended but still chunky.", "Add garlic powder, salt, and pepper to taste.", "Refrigerate for at least 30 minutes before serving for flavors to meld."]	2026-03-05 12:48:20.975229	ianw
14	Spicy Blue Cheese Sauce	["1/2 cup crumbled blue cheese", "1/4 cup sour cream", "1/4 cup mayonnaise", "1 tablespoon lemon juice", "1/2 teaspoon garlic powder", "1-2 tablespoons hot sauce", "Salt and pepper to taste"]	["In a bowl, combine blue cheese, sour cream, mayonnaise, and lemon juice.", "Mix until well blended but still chunky.", "Add garlic powder, hot sauce, salt, and pepper to taste.", "Refrigerate for at least 30 minutes before serving to allow flavors to meld."]	2026-03-05 12:48:43.663178	ianw
15	Chocolate Cake	["2 cups all-purpose flour", "2 cups sugar", "3/4 cup cocoa powder", "1 and 1/2 teaspoons baking powder", "1 and 1/2 teaspoons baking soda", "1 teaspoon salt", "2 large eggs", "1 cup whole milk", "1/2 cup vegetable oil", "2 teaspoons vanilla extract", "1 cup boiling water"]	["Preheat your oven to 350°F (175°C).", "In a large bowl, mix together the flour, sugar, cocoa powder, baking powder, baking soda, and salt.", "Add the eggs, milk, oil, and vanilla extract to the dry ingredients and mix until well combined.", "Carefully stir in the boiling water (the batter will be thin).", "Pour the batter evenly into greased cake pans.", "Bake for 30-35 minutes or until a toothpick inserted into the center comes out clean.", "Allow the cakes to cool in the pans for 10 minutes before transferring to a wire rack to cool completely."]	2026-03-06 13:41:06.525105	ianw
17	Spaghetti Bolognese	["400g spaghetti", "2 tablespoons olive oil", "1 onion, chopped", "2 garlic cloves, minced", "400g minced beef", "2 carrots, diced", "2 celery sticks, diced", "400g can diced tomatoes", "2 tablespoons tomato paste", "1 teaspoon dried oregano", "1 teaspoon dried basil", "Salt and pepper to taste", "Grated Parmesan cheese, for serving"]	["Cook the spaghetti according to the package instructions; drain and set aside.", "In a large skillet, heat olive oil over medium heat and sauté onion and garlic until soft.", "Add the minced beef and cook until browned.", "Stir in the carrots and celery, cooking for about 5 minutes until softened.", "Add the diced tomatoes, tomato paste, oregano, basil, salt, and pepper. Simmer for 20 minutes.", "Serve the sauce over the spaghetti and top with grated Parmesan cheese."]	2026-03-10 09:50:30.371487	ianw
16	Lasagna	["12 lasagna noodles", "2 tablespoons olive oil", "1 onion, chopped", "3 cloves garlic, minced", "1 pound ground beef", "1 (28-ounce) can crushed tomatoes", "2 (6-ounce) cans tomato paste", "2 teaspoons dried basil", "1 teaspoon dried oregano", "Salt and pepper to taste", "15 ounces ricotta cheese", "1 egg", "3 cups shredded mozzarella cheese", "3/4 cup grated Parmesan cheese"]	["Preheat your oven to 375°F (190°C).", "Cook the lasagna noodles according to package instructions; drain and set aside.", "In a large skillet, heat olive oil over medium heat. Add onion and garlic; sauté until soft.", "Add ground beef, cooking until browned. Drain excess fat.", "Stir in crushed tomatoes, tomato paste, basil, oregano, salt, and pepper. Simmer for 30 minutes.", "In a bowl, mix the ricotta cheese, egg, and a pinch of salt and pepper.", "In a baking dish, spread a layer of meat sauce, followed by a layer of noodles, then a layer of the ricotta mixture, and then a layer of mozzarella cheese. Repeat layers, finishing with meat sauce and a layer of mozzarella and Parmesan cheese on top.", "Cover with aluminum foil and bake for 25 minutes. Remove foil and bake for an additional 25 minutes or until cheese is bubbly and golden.", "Let stand for 15 minutes before serving."]	2026-03-06 13:44:26.125541	ianw
18	Tangy Mushroom Sauce	["500g mushrooms, sliced", "2 tablespoons olive oil", "1 onion, finely chopped", "2 garlic cloves, minced", "1 tablespoon Worcestershire sauce", "2 tablespoons soy sauce", "1 tablespoon lemon juice", "1 cup vegetable broth", "1 tablespoon cornstarch (mixed with 2 tablespoons water)", "Salt and pepper to taste", "Fresh parsley, chopped (for garnish)"]	["In a skillet, heat olive oil over medium heat. Add chopped onion and garlic, sauté until translucent.", "Add the sliced mushrooms and cook until they are golden brown, about 5-7 minutes.", "Stir in Worcestershire sauce, soy sauce, and lemon juice, mixing well.", "Add vegetable broth and bring to a simmer. Cook for 5 minutes.", "Slowly stir in the cornstarch mixture to thicken the sauce, cooking for another 2-3 minutes until it reaches your desired consistency.", "Season with salt and pepper to taste.", "Serve warm, garnished with chopped parsley."]	2026-03-10 10:04:04.776362	ianw
