fde122a8-d1cb-46a2-bd7e-e99e0255d68f	TRnadRFngN9ux_kvXHF4V	Ian Wegerle	2026-03-10 10:40:37.086+00	2026-03-10 10:40:37.086+00	[{"parameters":{"httpMethod":"POST","path":"agent","responseMode":"responseNode","options":{}},"type":"n8n-nodes-base.webhook","typeVersion":2.1,"position":[-480,-48],"id":"17058827-c093-4507-994e-f8a856f00e8b","name":"Webhook","webhookId":"cc96b602-73e7-44c8-9459-21c687a5e164"},{"parameters":{"promptType":"define","text":"={{ $('Webhook').item.json.body.message }}","options":{"systemMessage":"=You are an AI recipe assistant.\\n\\nYou have tools that allow you to access and manage recipes.\\n\\nUse tools whenever possible when interacting with stored recipes.\\n\\nIf a recipe does not exist, you may generate a new recipe.\\n\\n----------------------------------------\\nAVAILABLE TOOLS\\n----------------------------------------\\n\\nget_recipes\\nReturns all saved recipes.\\n\\nget_recipe\\nReturns a single recipe by id.\\n\\ncreate_recipe\\nCreates and saves a new recipe.\\n\\ndelete_recipe\\nDeletes a recipe by id.\\n\\n----------------------------------------\\nCREATING RECIPES\\n----------------------------------------\\n\\nIf a user asks for a recipe that does not already exist:\\n\\n1. Generate the recipe.\\n2. Save it using the create_recipe tool.\\n3. Confirm to the user that the recipe was saved.\\n\\nWhen calling create_recipe you  MUST include:\\n\\ntitle\\ningredients\\ninstructions\\n\\nand you MUST return tool arguments in this exact structure:\\n\\n{\\n\\"title\\": \\"Chocolate Cake\\",\\n\\"ingredients\\": [\\n\\"2 cups flour\\",\\n\\"1 cup sugar\\",\\n\\"3/4 cup cocoa powder\\"\\n],\\n\\"instructions\\": [\\n\\"Preheat oven to 180C\\",\\n\\"Mix ingredients\\",\\n\\"Bake for 30 minutes\\"\\n]\\n}\\n\\nRules:\\n- ingredients MUST be an array of strings\\n- instructions MUST be an array of strings\\n- NEVER return ingredients or instructions as a single string\\n\\n----------------------------------------\\nSHOWING RECIPES\\n----------------------------------------\\n\\nIf the user asks to see recipes:\\n\\nUse get_recipes.\\n\\nIf the user asks for a specific recipe:\\n\\n1. Use get_recipes\\n2. Find the recipe with the closest matching title\\n3. Extract its id\\n4. Use get_recipe\\n\\n----------------------------------------\\nDELETING RECIPES\\n----------------------------------------\\n\\nIf the user asks to delete a recipe:\\n\\n1. Use get_recipes\\n2. Find the matching title\\n3. Extract its id\\n4. Use delete_recipe"}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":3.1,"position":[224,-48],"id":"c1424d13-aa65-4c89-a653-7eeddfd75d06","name":"AI Agent"},{"parameters":{"model":{"__rl":true,"value":"gpt-4o-mini","mode":"list","cachedResultName":"gpt-4o-mini"},"builtInTools":{},"options":{}},"type":"@n8n/n8n-nodes-langchain.lmChatOpenAi","typeVersion":1.3,"position":[-32,176],"id":"237f1faf-33c9-4e9e-a1e1-808bf33075e5","name":"OpenAI Chat Model","credentials":{"openAiApi":{"id":"I9fdheTt0Ds7nlEN","name":"OpenAi account"}}},{"parameters":{"sessionIdType":"customKey","sessionKey":"={{ $json.sessionId }}"},"type":"@n8n/n8n-nodes-langchain.memoryPostgresChat","typeVersion":1.3,"position":[96,176],"id":"1b794ee6-340b-45eb-8445-48f6ff5bdad4","name":"Postgres Chat Memory","credentials":{"postgres":{"id":"8jMCgDVlELMJ97MX","name":"n8n-chat"}}},{"parameters":{"assignments":{"assignments":[{"id":"522bbceb-affc-4fb6-845f-74f360157b23","name":"sessionId","value":"=sessionId = {{ $json.headers['x-session-id'] || $json.headers['x-forwarded-for'] || $json.ip }}","type":"string"},{"id":"94ac12bc-87a0-4442-8a33-ce9eea1079a8","name":"message","value":"={{ $json.body.prompt }}","type":"string"}]},"options":{}},"type":"n8n-nodes-base.set","typeVersion":3.4,"position":[-256,-48],"id":"7808a46d-35ac-4924-b90d-d4e42c4f66e1","name":"Edit Fields"},{"parameters":{"respondWith":"json","responseBody":"={\\n\\"message\\": {{$json[\\"output\\"]}}\\n}","options":{"responseCode":200,"responseHeaders":{"entries":[